<?php
$search=trim((string)($_GET['q']??'')); $status=(string)($_GET['status']??''); $where=' WHERE 1=1'; $params=[];
if($search!==''){ $where.=' AND (c.name LIKE ? OR p.name LIKE ?)'; $params=['%'.$search.'%','%'.$search.'%']; }
if(in_array($status,['trial','active','past_due','paused','canceled'],true)){ $where.=' AND s.status=?'; $params[]=$status; }
$countSql='SELECT COUNT(*) FROM subscriptions s JOIN clients c ON c.id=s.client_id JOIN products p ON p.id=s.product_id'.$where;
$dataSql="SELECT s.*,c.name client,c.country,p.name product,p.billing_cycle,((s.unit_price*s.quantity)-s.discount) recurring_value FROM subscriptions s JOIN clients c ON c.id=s.client_id JOIN products p ON p.id=s.product_id{$where} ORDER BY FIELD(s.status,'past_due','trial','active','paused','canceled'),s.next_billing_date";
$pagination=pagination($db,$countSql,$dataSql,$params);
$edit=isset($_GET['edit'])?$db->fetch('SELECT * FROM subscriptions WHERE id=?',[(int)$_GET['edit']]):null; $showForm=isset($_GET['new'])||$edit;
$clients=$showForm?$db->fetchAll("SELECT id,name,country,preferred_currency FROM clients WHERE status!='inactive' OR id=? ORDER BY name",[(int)($edit['client_id']??0)]):[];
$products=$showForm?$db->fetchAll('SELECT * FROM products WHERE active=1 OR id=? ORDER BY name',[(int)($edit['product_id']??0)]):[];
$activeCount=(int)$db->value("SELECT COUNT(*) FROM subscriptions WHERE status='active'");
$trialCount=(int)$db->value("SELECT COUNT(*) FROM subscriptions WHERE status='trial'");
$overdueCount=(int)$db->value("SELECT COUNT(*) FROM subscriptions WHERE status='past_due'");
$dueCount=(int)$db->value("SELECT COUNT(*) FROM subscriptions WHERE status IN ('active','trial','past_due') AND next_billing_date IS NOT NULL AND next_billing_date<=CURDATE()");
?>
<section class="mini-stats"><div><span class="dot green"></span><b><?= $activeCount ?></b><small>Ativas</small></div><div><span class="dot gold"></span><b><?= $trialCount ?></b><small>Em teste</small></div><div><span class="dot red"></span><b><?= $overdueCount ?></b><small>Em atraso</small></div></section>
<section class="toolbar list-toolbar"><form class="search-filters" method="get"><input type="hidden" name="page" value="subscriptions"><label class="search-box">⌕<input name="q" placeholder="Buscar cliente ou produto" value="<?= h($search) ?>"></label><select name="status" onchange="this.form.submit()"><option value="">Todos os status</option><?php foreach(['active'=>'Ativas','trial'=>'Em teste','past_due'=>'Em atraso','paused'=>'Pausadas','canceled'=>'Canceladas'] as $value=>$label): ?><option value="<?= $value ?>" <?= $status===$value?'selected':'' ?>><?= $label ?></option><?php endforeach; ?></select><button class="button secondary">Buscar</button></form><div><a class="button ghost" href="?page=export&type=subscriptions">⇩ Exportar</a><?php if($auth->canWrite()&&$dueCount>0): ?><form method="post" class="inline-form" data-confirm="Gerar todos os pagamentos pendentes até hoje? Nada será cobrado automaticamente."><?= csrf_field() ?><input type="hidden" name="action" value="generate_due_payments"><button class="button secondary">Gerar <?= $dueCount ?> vencida(s)</button></form><?php endif; ?><?php if($auth->canWrite()): ?><a class="button primary" href="?page=subscriptions&new=1">＋ Nova assinatura</a><?php endif; ?></div></section>
<section class="card table-card"><div class="table-meta"><span><b><?= $pagination['total'] ?></b> assinaturas</span></div><div class="table-wrap"><table><thead><tr><th>Cliente / Produto</th><th>Valor recorrente</th><th>Ciclo</th><th>Próxima cobrança</th><th>Status</th><th></th></tr></thead><tbody>
<?php if(!$pagination['rows']): ?><tr><td colspan="6" class="empty-cell">Nenhuma assinatura encontrada.</td></tr><?php endif; ?>
<?php foreach($pagination['rows'] as $item): ?><tr><td><div class="entity"><span class="avatar-sm"><?= h(mb_strtoupper(mb_substr($item['client'],0,1))) ?></span><span><b><?= h($item['client']) ?></b><small><?= h($item['product']) ?> · <?= $item['country']==='BR'?'🇧🇷':'🇺🇸' ?></small></span></div></td><td><b><?= money($item['recurring_value'],$item['currency']) ?></b><small class="block"><?= (int)$item['quantity'] ?> unidade(s)</small></td><td><?= cycle_label($item['billing_cycle']) ?></td><td><?= date_br($item['next_billing_date']) ?></td><td><span class="badge <?= status_class($item['status']) ?>"><?= status_label($item['status']) ?></span></td><td><a class="row-action" href="?page=subscriptions&edit=<?= (int)$item['id'] ?>">•••</a></td></tr><?php endforeach; ?>
</tbody></table></div><?= render_pagination($pagination) ?></section>
<?php if($showForm): ?><div class="modal open"><a class="modal-backdrop" href="?page=subscriptions"></a><section class="modal-panel wide"><header><div><p class="eyebrow">RECEITA RECORRENTE</p><h2><?= $edit?'Editar assinatura':'Nova assinatura' ?></h2></div><a href="?page=subscriptions" class="modal-close">×</a></header><form method="post" class="form-grid" data-subscription-form><?= csrf_field() ?><input type="hidden" name="action" value="save_subscription"><input type="hidden" name="id" value="<?= (int)($edit['id']??0) ?>"><input type="hidden" name="_return" value="<?= h($_SERVER['REQUEST_URI']) ?>">
<label>Cliente<select name="client_id" required data-sub-client><option value="">Selecione…</option><?php foreach($clients as $client): ?><option value="<?= (int)$client['id'] ?>" data-currency="<?= h($client['preferred_currency']) ?>" <?= (int)($edit['client_id']??0)===(int)$client['id']?'selected':'' ?>><?= h($client['name']) ?> · <?= h($client['country']) ?></option><?php endforeach; ?></select></label><label>Produto<select name="product_id" required data-sub-product><option value="">Selecione…</option><?php foreach($products as $product): ?><option value="<?= (int)$product['id'] ?>" data-brl="<?= h($product['price_brl']) ?>" data-usd="<?= h($product['price_usd']) ?>" <?= (int)($edit['product_id']??0)===(int)$product['id']?'selected':'' ?>><?= h($product['name']) ?> · <?= cycle_label($product['billing_cycle']) ?></option><?php endforeach; ?></select></label><label>Moeda<select name="currency" data-sub-currency><option value="BRL" <?= ($edit['currency']??'BRL')==='BRL'?'selected':'' ?>>BRL — Real</option><option value="USD" <?= ($edit['currency']??'')==='USD'?'selected':'' ?>>USD — Dólar</option></select></label><label>Valor unitário<input name="unit_price" type="number" step="0.01" min="0" required value="<?= decimal_input($edit['unit_price']??0) ?>" data-sub-price></label><label>Quantidade<input name="quantity" type="number" min="1" required value="<?= (int)($edit['quantity']??1) ?>"></label><label>Desconto total<input name="discount" type="number" step="0.01" min="0" value="<?= decimal_input($edit['discount']??0) ?>"></label><label>Data de início<input name="start_date" type="date" required value="<?= h($edit['start_date']??date('Y-m-d')) ?>"></label><label>Próxima cobrança<input name="next_billing_date" type="date" value="<?= h($edit['next_billing_date']??date('Y-m-d',strtotime('+1 month'))) ?>"></label><label>Status<select name="status"><option value="active" <?= ($edit['status']??'active')==='active'?'selected':'' ?>>Ativa</option><option value="trial" <?= ($edit['status']??'')==='trial'?'selected':'' ?>>Teste</option><option value="past_due" <?= ($edit['status']??'')==='past_due'?'selected':'' ?>>Em atraso</option><option value="paused" <?= ($edit['status']??'')==='paused'?'selected':'' ?>>Pausada</option><option value="canceled" <?= ($edit['status']??'')==='canceled'?'selected':'' ?>>Cancelada</option></select></label><label>Data de cancelamento<input name="canceled_at" type="date" value="<?= h($edit['canceled_at']??'') ?>"></label><label class="span-2">Forma de pagamento<input name="payment_method" value="<?= h($edit['payment_method']??'') ?>" placeholder="Cartão, PIX, Stripe, boleto…"></label><label class="span-2">Observações<textarea name="notes" rows="3"><?= h($edit['notes']??'') ?></textarea></label><footer class="span-2"><a class="button ghost" href="?page=subscriptions">Cancelar</a><button class="button primary">Salvar assinatura</button></footer></form><?php if($edit&&$auth->canWrite()): ?><form method="post" class="danger-zone" data-confirm="Excluir esta assinatura?"><?= csrf_field() ?><input type="hidden" name="action" value="delete_subscription"><input type="hidden" name="id" value="<?= (int)$edit['id'] ?>"><button>Excluir assinatura</button></form><?php endif; ?></section></div><?php endif; ?>
